import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote — base premiums per item type (first insurance: +10%, +5G fee, round up)
  it.todo("should quote a single sword for a new customer");
  it.todo("should quote a single amulet for a new customer");
  it.todo("should quote a single staff for a new customer");
  it.todo("should quote a single potion for a new customer");
  it.todo("should quote a single component for a new customer");

  // Component bundle rule
  it.todo("should price a bundle of 3 alike components at the special 60 G base premium");

  // Modifiers
  it.todo("should add a 50% surcharge for cursed items");
  it.todo("should add a 30% surcharge for highly enchanted items (enchantment >= 5)");
  it.todo("should apply a 20% loyalty discount for customers with >= 2 years");
  it.todo("should apply a 15% discount on each contract after the first");

  // Rounding
  it.todo("should round the premium up to whole G (in MHPCO's favor)");

  // Claims
  it.todo("should pay out a basic claim minus the 100 G deductible");
  it.todo("should reimburse damage to highly enchanted items (>= 8) at 50%");
  it.todo("should fully reimburse damage to dragon-material items");
  it.todo("should cap total payouts at twice the insurance sum and report remaining cap");
});

