export interface Item {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
}

export interface QuoteStep {
  op: "quote";
  items: Item[];
}

export interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

export interface QuoteResult {
  premium: number;
}

export interface Result {
  results: QuoteResult[];
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

export const runScenario = (scenario: Scenario): Result => {
  const results = scenario.steps.map((step) => {
    const base = step.items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
    const withFirst = base * 1.1;
    const withFee = withFirst + 5;
    return { premium: Math.ceil(withFee) };
  });
  return { results };
};

