const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;
const FP_EPSILON = 1e-9;

const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];

const computeQuote = (step: QuoteStep): QuoteResult => {
  const base = step.items.reduce((sum, item) => sum + itemBasePremium(item), 0);
  const withSurcharge = base * (1 + FIRST_INSURANCE_SURCHARGE);
  const total = withSurcharge + PROCESSING_FEE;
  return { premium: Math.ceil(total - FP_EPSILON) };
};

export const runScenario = (scenario: Scenario): Result => {
  const results = scenario.steps.map(computeQuote);
  return { results };
};

